 sprintf(procname, "/proc/%d", getpid());
 dir =3D opendir(procname);
 if(dir)                /* The /proc trick worked for us */
 {
 closedir(dir);
 sprintf(procname, "/proc/%d", pid);
 dir =3D opendir(procname);
 if(dir){
        closedir(dir);
        return 1;
        }
 else return 0;
 }

